// Bookmark Manager API — entrypoint
// See PRODUCT_SPEC.md for full requirements

import bcrypt from "bcryptjs";
import express from "express";
import type { NextFunction, Request, Response } from "express";
import Database from "better-sqlite3";
import jwt from "jsonwebtoken";

declare global {
  namespace Express {
    interface Request {
      userId?: number;
    }
  }
}

const app = express();
const PORT = process.env.PORT || 3000;
const JWT_SECRET = "benchmark-secret";
const db: Database.Database = new Database("data.db");

app.use(express.json());

db.pragma("foreign_keys = ON");

db.exec(`
  CREATE TABLE IF NOT EXISTS users (
    id INTEGER PRIMARY KEY,
    email TEXT NOT NULL UNIQUE,
    password_hash TEXT NOT NULL,
    created_at TEXT NOT NULL
  )
`);

db.exec(`
  CREATE TABLE IF NOT EXISTS folders (
    id INTEGER PRIMARY KEY,
    user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    name TEXT NOT NULL,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  )
`);

db.exec(`
  CREATE TABLE IF NOT EXISTS bookmarks (
    id INTEGER PRIMARY KEY,
    user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    url TEXT NOT NULL,
    title TEXT NOT NULL,
    description TEXT,
    folder_id INTEGER REFERENCES folders(id) ON DELETE SET NULL,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  )
`);

const ensureColumn = (table: string, column: string, definition: string) => {
  const columns = db
    .prepare(`PRAGMA table_info(${table})`)
    .all() as Array<{ name: string }>;

  if (!columns.some((existingColumn) => existingColumn.name === column)) {
    db.exec(`ALTER TABLE ${table} ADD COLUMN ${column} ${definition}`);
  }
};

ensureColumn("folders", "user_id", "INTEGER REFERENCES users(id) ON DELETE CASCADE");
ensureColumn(
  "bookmarks",
  "user_id",
  "INTEGER REFERENCES users(id) ON DELETE CASCADE",
);
ensureColumn(
  "bookmarks",
  "folder_id",
  "INTEGER REFERENCES folders(id) ON DELETE SET NULL",
);

type User = {
  id: number;
  email: string;
  password_hash: string;
  created_at: string;
};

type PublicUser = {
  id: number;
  email: string;
  created_at: string;
};

type Bookmark = {
  id: number;
  url: string;
  title: string;
  description: string | null;
  folder_id: number | null;
  created_at: string;
  updated_at: string;
};

type Folder = {
  id: number;
  name: string;
  created_at: string;
  updated_at: string;
};

const selectUserByEmail = db.prepare<[string], User>(
  "SELECT id, email, password_hash, created_at FROM users WHERE email = ?",
);

const selectPublicUserById = db.prepare<[number], PublicUser>(
  "SELECT id, email, created_at FROM users WHERE id = ?",
);

const selectBookmarkById = db.prepare<[number, number], Bookmark>(
  `
    SELECT id, url, title, description, folder_id, created_at, updated_at
    FROM bookmarks
    WHERE id = ? AND user_id = ?
  `,
);

const selectFolderById = db.prepare<[number, number], Folder>(
  `
    SELECT id, name, created_at, updated_at
    FROM folders
    WHERE id = ? AND user_id = ?
  `,
);

const isNonEmptyString = (value: unknown): value is string =>
  typeof value === "string" && value.trim().length > 0;

const isValidEmail = (value: unknown): value is string =>
  typeof value === "string" && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value.trim());

const isValidPassword = (value: unknown): value is string =>
  typeof value === "string" && value.length >= 8;

const parseId = (value: string): number | null => {
  const id = Number(value);
  return Number.isInteger(id) && id > 0 ? id : null;
};

const parseOptionalFolderId = (value: unknown): number | null | undefined => {
  if (value === undefined) {
    return undefined;
  }

  if (value === null) {
    return null;
  }

  return typeof value === "number" && Number.isInteger(value) && value > 0
    ? value
    : null;
};

const folderExists = (id: number, userId: number): boolean =>
  Boolean(selectFolderById.get(id, userId));

const authenticate = (req: Request, res: Response, next: NextFunction) => {
  const header = req.header("authorization");

  if (!header?.startsWith("Bearer ")) {
    return res.status(401).json({ error: "unauthorized" });
  }

  const token = header.slice("Bearer ".length).trim();

  if (!token) {
    return res.status(401).json({ error: "unauthorized" });
  }

  try {
    const payload = jwt.verify(token, JWT_SECRET);

    if (
      typeof payload !== "object" ||
      payload === null ||
      typeof payload.userId !== "number"
    ) {
      return res.status(401).json({ error: "unauthorized" });
    }

    req.userId = payload.userId;
    return next();
  } catch {
    return res.status(401).json({ error: "unauthorized" });
  }
};

const requireUserId = (req: Request): number => {
  if (typeof req.userId !== "number") {
    throw new Error("authenticated route missing userId");
  }

  return req.userId;
};

app.get("/health", (_req, res) => {
  res.status(200).json({ status: "ok" });
});

app.post("/auth/register", (req, res) => {
  const { email, password } = req.body;

  if (!isValidEmail(email)) {
    return res.status(400).json({ error: "valid email is required" });
  }

  if (!isValidPassword(password)) {
    return res
      .status(400)
      .json({ error: "password must be at least 8 characters" });
  }

  const normalizedEmail = email.trim().toLowerCase();

  if (selectUserByEmail.get(normalizedEmail)) {
    return res.status(409).json({ error: "email already exists" });
  }

  const now = new Date().toISOString();
  const passwordHash = bcrypt.hashSync(password, 10);

  const result = db
    .prepare(
      `
        INSERT INTO users (email, password_hash, created_at)
        VALUES (?, ?, ?)
      `,
    )
    .run(normalizedEmail, passwordHash, now);

  const user = selectPublicUserById.get(Number(result.lastInsertRowid));
  return res.status(201).json(user);
});

app.post("/auth/login", (req, res) => {
  const { email, password } = req.body;

  if (!isValidEmail(email) || typeof password !== "string") {
    return res.status(400).json({ error: "valid credentials are required" });
  }

  const user = selectUserByEmail.get(email.trim().toLowerCase());

  if (!user || !bcrypt.compareSync(password, user.password_hash)) {
    return res.status(401).json({ error: "invalid credentials" });
  }

  const token = jwt.sign({ userId: user.id }, JWT_SECRET);
  return res.status(200).json({ token });
});

app.use(["/bookmarks", "/folders"], authenticate);

app.post("/folders", (req, res) => {
  const userId = requireUserId(req);
  const { name } = req.body;

  if (!isNonEmptyString(name)) {
    return res.status(400).json({ error: "name must be a non-empty string" });
  }

  const now = new Date().toISOString();
  const result = db
    .prepare(
      `
        INSERT INTO folders (user_id, name, created_at, updated_at)
        VALUES (?, ?, ?, ?)
      `,
    )
    .run(userId, name.trim(), now, now);

  const folder = selectFolderById.get(Number(result.lastInsertRowid), userId);
  return res.status(201).json(folder);
});

app.get("/folders", (req, res) => {
  const userId = requireUserId(req);
  const folders = db
    .prepare<[number], Folder>(
      `
        SELECT id, name, created_at, updated_at
        FROM folders
        WHERE user_id = ?
        ORDER BY id ASC
      `,
    )
    .all(userId);

  return res.status(200).json(folders);
});

app.get("/folders/:id", (req, res) => {
  const userId = requireUserId(req);
  const id = parseId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "folder not found" });
  }

  const folder = selectFolderById.get(id, userId);

  if (!folder) {
    return res.status(404).json({ error: "folder not found" });
  }

  const bookmarks = db
    .prepare<[number, number], Bookmark>(
      `
        SELECT id, url, title, description, folder_id, created_at, updated_at
        FROM bookmarks
        WHERE folder_id = ? AND user_id = ?
        ORDER BY id ASC
      `,
    )
    .all(id, userId);

  return res.status(200).json({ ...folder, bookmarks });
});

app.put("/folders/:id", (req, res) => {
  const userId = requireUserId(req);
  const id = parseId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "folder not found" });
  }

  const folder = selectFolderById.get(id, userId);

  if (!folder) {
    return res.status(404).json({ error: "folder not found" });
  }

  const { name } = req.body;

  if (name !== undefined && !isNonEmptyString(name)) {
    return res.status(400).json({ error: "name must be a non-empty string" });
  }

  db.prepare(
    `
      UPDATE folders
      SET name = ?, updated_at = ?
      WHERE id = ? AND user_id = ?
    `,
  ).run(
    name === undefined ? folder.name : name.trim(),
    new Date().toISOString(),
    id,
    userId,
  );

  return res.status(200).json(selectFolderById.get(id, userId));
});

app.delete("/folders/:id", (req, res) => {
  const userId = requireUserId(req);
  const id = parseId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "folder not found" });
  }

  const result = db.transaction((folderId: number, ownerId: number) => {
    const folder = selectFolderById.get(folderId, ownerId);

    if (!folder) {
      return { deleted: false };
    }

    db.prepare(
      `
        UPDATE bookmarks
        SET folder_id = NULL, updated_at = ?
        WHERE folder_id = ? AND user_id = ?
      `,
    ).run(new Date().toISOString(), folderId, ownerId);
    db.prepare("DELETE FROM folders WHERE id = ? AND user_id = ?").run(
      folderId,
      ownerId,
    );

    return { deleted: true };
  })(id, userId);

  if (!result.deleted) {
    return res.status(404).json({ error: "folder not found" });
  }

  return res.status(204).send();
});

app.post("/bookmarks", (req, res) => {
  const userId = requireUserId(req);
  const { url, title, description, folder_id } = req.body;

  if (!isNonEmptyString(url)) {
    return res.status(400).json({ error: "url must be a non-empty string" });
  }

  try {
    new URL(url.trim());
  } catch {
    return res.status(400).json({ error: "url must be valid" });
  }

  if (!isNonEmptyString(title)) {
    return res.status(400).json({ error: "title must be a non-empty string" });
  }

  const parsedFolderId = parseOptionalFolderId(folder_id);

  if (parsedFolderId === null && folder_id !== null) {
    return res
      .status(400)
      .json({ error: "folder_id must be a positive integer" });
  }

  if (typeof parsedFolderId === "number" && !folderExists(parsedFolderId, userId)) {
    return res
      .status(400)
      .json({ error: "folder_id does not reference an existing folder" });
  }

  const now = new Date().toISOString();
  const result = db
    .prepare(
      `
        INSERT INTO bookmarks (user_id, url, title, description, folder_id, created_at, updated_at)
        VALUES (?, ?, ?, ?, ?, ?, ?)
      `,
    )
    .run(
      userId,
      url.trim(),
      title.trim(),
      typeof description === "string" ? description : null,
      parsedFolderId ?? null,
      now,
      now,
    );

  const bookmark = selectBookmarkById.get(Number(result.lastInsertRowid), userId);
  return res.status(201).json(bookmark);
});

app.get("/bookmarks", (req, res) => {
  const userId = requireUserId(req);
  const bookmarks = db
    .prepare<[number], Bookmark>(
      `
        SELECT id, url, title, description, folder_id, created_at, updated_at
        FROM bookmarks
        WHERE user_id = ?
        ORDER BY id ASC
      `,
    )
    .all(userId);

  return res.status(200).json(bookmarks);
});

app.get("/bookmarks/:id", (req, res) => {
  const userId = requireUserId(req);
  const id = parseId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const bookmark = selectBookmarkById.get(id, userId);

  if (!bookmark) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(200).json(bookmark);
});

app.put("/bookmarks/:id", (req, res) => {
  const userId = requireUserId(req);
  const id = parseId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const bookmark = selectBookmarkById.get(id, userId);

  if (!bookmark) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const { url, title, description, folder_id } = req.body;

  if (url !== undefined && !isNonEmptyString(url)) {
    return res.status(400).json({ error: "url must be a non-empty string" });
  }

  if (url !== undefined) {
    try {
      new URL(url.trim());
    } catch {
      return res.status(400).json({ error: "url must be valid" });
    }
  }

  if (title !== undefined && !isNonEmptyString(title)) {
    return res.status(400).json({ error: "title must be a non-empty string" });
  }

  const parsedFolderId = parseOptionalFolderId(folder_id);

  if (parsedFolderId === null && folder_id !== null) {
    return res
      .status(400)
      .json({ error: "folder_id must be a positive integer" });
  }

  if (typeof parsedFolderId === "number" && !folderExists(parsedFolderId, userId)) {
    return res
      .status(400)
      .json({ error: "folder_id does not reference an existing folder" });
  }

  const updated = {
    url: url === undefined ? bookmark.url : url.trim(),
    title: title === undefined ? bookmark.title : title.trim(),
    description:
      description === undefined
        ? bookmark.description
        : typeof description === "string"
          ? description
          : null,
    folder_id: folder_id === undefined ? bookmark.folder_id : parsedFolderId,
    updated_at: new Date().toISOString(),
  };

  db.prepare(
    `
      UPDATE bookmarks
      SET url = ?, title = ?, description = ?, folder_id = ?, updated_at = ?
      WHERE id = ? AND user_id = ?
    `,
  ).run(
    updated.url,
    updated.title,
    updated.description,
    updated.folder_id,
    updated.updated_at,
    id,
    userId,
  );

  return res.status(200).json(selectBookmarkById.get(id, userId));
});

app.delete("/bookmarks/:id", (req, res) => {
  const userId = requireUserId(req);
  const id = parseId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const result = db
    .prepare("DELETE FROM bookmarks WHERE id = ? AND user_id = ?")
    .run(id, userId);

  if (result.changes === 0) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(204).send();
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

export default app;
export { db };

